'use client';

import Link from 'next/link';
import { usePathname, useRouter } from 'next/navigation';
import { Zap, TrendingUp, User, Settings, Hexagon, PanelLeftClose, PanelLeftOpen, LogIn, LogOut } from 'lucide-react';
import { useState } from 'react';
import { useAuthStore } from '@/store/authStore';

const navItems = [
  { icon: Zap,        label: '결정 피드', path: '/feed' },
  { icon: TrendingUp, label: '트렌드',    path: '/trends' },
  { icon: User,       label: '프로필',    path: '/profile' },
];

export function Sidebar() {
  const pathname = usePathname();
  const router = useRouter();
  const [collapsed, setCollapsed] = useState(false);
  const { user, signOut } = useAuthStore();

  async function handleSignOut() {
    await signOut();
    router.push('/');
    router.refresh();
  }

  return (
    <aside className={`h-screen sticky top-0 bg-surface-base border-r border-surface-border flex-col hidden md:flex transition-all duration-300 ${collapsed ? 'w-16' : 'w-64'}`}>

      {/* 로고 + 토글 */}
      <div className="h-16 flex items-center justify-between px-4 border-b border-surface-border shrink-0">
        <Link href="/" className={`flex items-center gap-2 text-white font-bold tracking-wider hover:opacity-80 transition-opacity ${collapsed ? 'justify-center w-full' : ''}`}>
          <Hexagon className="w-6 h-6 text-brand-500 fill-brand-500/20 shrink-0" />
          {!collapsed && <span>KITPICK</span>}
        </Link>
        {!collapsed && (
          <button onClick={() => setCollapsed(true)} className="p-1.5 rounded-lg text-zinc-500 hover:text-zinc-200 hover:bg-surface-raised transition-colors" aria-label="메뉴 닫기">
            <PanelLeftClose className="w-4 h-4" />
          </button>
        )}
      </div>

      {collapsed && (
        <div className="flex justify-center pt-3 px-2">
          <button onClick={() => setCollapsed(false)} className="p-1.5 rounded-lg text-zinc-500 hover:text-zinc-200 hover:bg-surface-raised transition-colors" aria-label="메뉴 열기">
            <PanelLeftOpen className="w-4 h-4" />
          </button>
        </div>
      )}

      {/* 네비게이션 */}
      <nav className="flex-1 px-3 py-6 space-y-1">
        {!collapsed && (
          <div className="px-3 mb-2 text-xs font-semibold text-zinc-500 uppercase tracking-wider">메뉴</div>
        )}
        {navItems.map((item) => {
          const isActive = pathname === item.path;
          return (
            <Link
              key={item.path}
              href={item.path}
              title={collapsed ? item.label : undefined}
              className={`flex items-center rounded-lg text-sm font-medium transition-colors ${collapsed ? 'justify-center p-2.5' : 'gap-3 px-3 py-2'} ${isActive ? 'bg-brand-500/10 text-brand-500' : 'text-zinc-400 hover:text-zinc-100 hover:bg-surface-raised'}`}
            >
              <item.icon className="w-4 h-4 shrink-0" />
              {!collapsed && item.label}
            </Link>
          );
        })}
      </nav>

      {/* 하단 — 로그인 상태에 따라 분기 */}
      <div className="p-4 border-t border-surface-border space-y-1">
        {user ? (
          <>
            {/* 유저 정보 */}
            {!collapsed && (
              <div className="flex items-center gap-2 px-3 py-2 mb-1">
                <div className="w-7 h-7 rounded-full bg-brand-500/20 border border-brand-500/30 flex items-center justify-center text-xs font-bold text-brand-400 shrink-0">
                  {(user.user_metadata?.username ?? user.email ?? '?')[0].toUpperCase()}
                </div>
                <div className="flex-1 min-w-0">
                  <p className="text-xs font-medium text-white truncate">
                    {user.user_metadata?.username ?? user.email?.split('@')[0]}
                  </p>
                  <p className="text-[10px] text-zinc-500 truncate">{user.email}</p>
                </div>
              </div>
            )}
            <button
              title={collapsed ? '설정' : undefined}
              className={`flex items-center rounded-lg text-sm font-medium text-zinc-400 hover:text-zinc-100 hover:bg-surface-raised transition-colors w-full ${collapsed ? 'justify-center p-2.5' : 'gap-3 px-3 py-2'}`}
            >
              <Settings className="w-4 h-4 shrink-0" />
              {!collapsed && '설정'}
            </button>
            <button
              onClick={handleSignOut}
              title={collapsed ? '로그아웃' : undefined}
              className={`flex items-center rounded-lg text-sm font-medium text-brand-500 hover:bg-brand-500/10 transition-colors w-full ${collapsed ? 'justify-center p-2.5' : 'gap-3 px-3 py-2'}`}
            >
              <LogOut className="w-4 h-4 shrink-0" />
              {!collapsed && '로그아웃'}
            </button>
          </>
        ) : (
          <Link
            href="/login"
            title={collapsed ? '로그인' : undefined}
            className={`flex items-center rounded-lg text-sm font-medium text-zinc-400 hover:text-zinc-100 hover:bg-surface-raised transition-colors w-full ${collapsed ? 'justify-center p-2.5' : 'gap-3 px-3 py-2'}`}
          >
            <LogIn className="w-4 h-4 shrink-0" />
            {!collapsed && '로그인'}
          </Link>
        )}
      </div>
    </aside>
  );
}
